def even_ele(nested):
    """
    Recursively extract all even integers from a nested mixed tuple.
    The function traverses tuples and lists at any depth, preserving
    the order of appearance, and returns a flat tuple of the even numbers.
    """
    result = []

    def _extract(item):
        # If the item is an integer, check evenness
        if isinstance(item, int):
            if item % 2 == 0:
                result.append(item)
        # If the item is a tuple or list, recurse into its elements
        elif isinstance(item, (tuple, list)):
            for sub in item:
                _extract(sub)
        # All other types are ignored

    _extract(nested)
    return tuple(result)
