from typing import List

def max_sum(arr: List[int]) -> int:
    """
    Return the maximum sum of a bitonic subsequence in the given array.
    A bitonic subsequence first strictly increases and then strictly decreases.
    The subsequence does not need to be contiguous.
    """
    n = len(arr)
    if n == 0:
        return 0

    # inc[i] = maximum sum of an increasing subsequence that ends at index i
    inc = arr.copy()  # each element alone forms a subsequence
    for i in range(n):
        for j in range(i):
            if arr[j] < arr[i] and inc[j] + arr[i] > inc[i]:
                inc[i] = inc[j] + arr[i]

    # dec[i] = maximum sum of a decreasing subsequence that starts at index i
    dec = arr.copy()
    for i in range(n - 1, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[j] < arr[i] and dec[j] + arr[i] > dec[i]:
                dec[i] = dec[j] + arr[i]

    # Combine increasing and decreasing parts; subtract arr[i] because it is counted twice
    max_bitonic = 0
    for i in range(n):
        current = inc[i] + dec[i] - arr[i]
        if current > max_bitonic:
            max_bitonic = current

    return max_bitonic
