def drop_empty(d):
    """
    Return a new dictionary with entries whose values are considered "empty" removed.
    An empty value is defined as:
        - None
        - An empty string (""), bytes (b""), or bytearray
        - An empty container (list, tuple, set, frozenset, dict, range) with length 0
    Numeric zero (0, 0.0) and False are retained because they are not "empty" in this context.
    """
    if not isinstance(d, dict):
        raise TypeError("Input must be a dictionary")

    result = {}
    for key, value in d.items():
        # Skip None explicitly
        if value is None:
            continue

        # Strings, bytes, bytearray: treat empty as empty
        if isinstance(value, (str, bytes, bytearray)):
            if len(value) == 0:
                continue

        # Containers that support len(): treat length 0 as empty
        elif isinstance(value, (list, tuple, set, frozenset, dict, range)):
            if len(value) == 0:
                continue

        # All other types (numbers, bool, custom objects) are kept
        result[key] = value

    return result
