def solution(a: int, b: int, n: int):
    """
    Find integers x and y such that a*x + b*y = n.

    Returns:
        (x, y) tuple of integers if a solution exists,
        None if there is no integer solution.
    """
    # Helper: extended Euclidean algorithm.
    def egcd(u, v):
        """
        Returns (g, x, y) where g = gcd(u, v) and x, y satisfy u*x + v*y = g.
        """
        if v == 0:
            return (abs(u), 1 if u > 0 else -1, 0)
        else:
            g, x1, y1 = egcd(v, u % v)
            # Back‑substitute to get coefficients for (u, v)
            x = y1
            y = x1 - (u // v) * y1
            return (g, x, y)

    # Special cases when both coefficients are zero.
    if a == 0 and b == 0:
        return (0, 0) if n == 0 else None

    # When one coefficient is zero, solve the simple linear equation.
    if a == 0:
        if b != 0 and n % b == 0:
            return (0, n // b)
        return None
    if b == 0:
        if a != 0 and n % a == 0:
            return (n // a, 0)
        return None

    # General case: use extended Euclidean algorithm.
    g, x0, y0 = egcd(a, b)

    # No solution if gcd does not divide n.
    if n % g != 0:
        return None

    # Scale the base solution to satisfy the target n.
    factor = n // g
    x = x0 * factor
    y = y0 * factor
    return (x, y)
