def maximum_value(tuple_list):
    """
    Find the maximum numeric value contained in any iterable element of the tuples
    within ``tuple_list``. If a tuple contains plain numeric elements, those are
    also considered. Returns ``None`` when no numeric values are found.

    Parameters
    ----------
    tuple_list : list[tuple]
        A list where each item is a tuple. The tuple may contain numbers,
        iterables of numbers (e.g., list, tuple, set), or other objects.

    Returns
    -------
    max_val : int | float | None
        The greatest numeric value discovered, or ``None`` if none exist.
    """
    # Helper to decide whether an object is an iterable of numbers (but not a string)
    def is_iterable_of_numbers(obj):
        if isinstance(obj, (str, bytes)):
            return False
        try:
            iter(obj)
        except TypeError:
            return False
        return True

    max_val = None

    for tup in tuple_list:
        # Ensure we are dealing with a tuple; skip otherwise
        if not isinstance(tup, tuple):
            continue
        for element in tup:
            # Direct numeric element
            if isinstance(element, (int, float)):
                if max_val is None or element > max_val:
                    max_val = element
            # Iterable containing numbers
            elif is_iterable_of_numbers(element):
                for item in element:
                    if isinstance(item, (int, float)):
                        if max_val is None or item > max_val:
                            max_val = item
            # Anything else is ignored
            else:
                continue

    return max_val
